//! Spec-compliance tests: Run Formatting & Fonts (ISO 29500-1 §17.3.2 + §17.8)
//!
//! These tests verify our implementation against specific OOXML run property
//! and font resolution constructs.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/runs-audit/create_docs.py`.

use stemma::{InlineNode, Mark};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/runs-audit";

// ── helpers ──────────────────────────────────────────────────────────────
fn text_nodes(p: &stemma::ParagraphNode) -> Vec<stemma::TextNode> {
    p.all_inlines_owned()
        .into_iter()
        .filter_map(|i| match i {
            InlineNode::Text(t) => Some(*t),
            _ => None,
        })
        .collect()
}

// ── 1. Complex script properties (bCs/iCs/szCs) ─────────────────────────

/// ISO 29500-1 §17.3.2.2: w:bCs with w:cs=true should produce Mark::Bold.
///
/// When cs is active, bCs determines bold instead of b.
/// POSITIVE: The style resolver maps bCs -> bold when cs is On.
#[test]
fn spec_bcs_with_cs_true_produces_bold() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "complex-script-props");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let cs_bold = nodes
        .iter()
        .find(|n| n.text.contains("CS bold"))
        .expect("should find 'CS bold run'");

    assert!(
        cs_bold.marks.contains(&Mark::Bold),
        "cs=true + bCs=true should produce Bold mark. \
         Got marks: {:?} for text '{}'",
        cs_bold.marks,
        cs_bold.text
    );
}

