/// ISO 29500-1 §17.3.2.39: w:szCs with w:cs=true overrides w:sz for font size.
///
/// POSITIVE: The style resolver uses szCs when cs is On.
#[test]
fn spec_szcs_with_cs_true_overrides_sz() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "complex-script-props");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let cs_bold = nodes
        .iter()
        .find(|n| n.text.contains("CS bold"))
        .expect("should find 'CS bold run'");

    // sz=24 (12pt) but szCs=32 (16pt); with cs=true, font_size should be 32
    assert_eq!(
        cs_bold.style_props.font_size,
        Some(32),
        "cs=true run should use szCs=32 (16pt) instead of sz=24 (12pt). \
         Got font_size={:?}",
        cs_bold.style_props.font_size
    );
}

/// MS-OI29500 §17.3.2.26(b): w:rtl=true activates complex script properties.
///
/// POSITIVE: rtl has the same effect as cs for bCs/iCs/szCs activation.
#[test]
fn spec_rtl_activates_bcs_and_ics() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "complex-script-props");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let rtl_run = nodes
        .iter()
        .find(|n| n.text.contains("RTL bold italic"))
        .expect("should find 'RTL bold italic run'");

    assert!(
        rtl_run.marks.contains(&Mark::Bold),
        "rtl=true + bCs=true should produce Bold. Got marks: {:?}",
        rtl_run.marks
    );
    assert!(
        rtl_run.marks.contains(&Mark::Italic),
        "rtl=true + iCs=true should produce Italic. Got marks: {:?}",
        rtl_run.marks
    );

    // szCs=36 (18pt) should be used
    assert_eq!(
        rtl_run.style_props.font_size,
        Some(36),
        "rtl=true run should use szCs=36 (18pt). Got font_size={:?}",
        rtl_run.style_props.font_size
    );
}

/// ISO 29500-1 §17.3.2.2: bCs without cs/rtl should NOT produce bold.
///
/// POSITIVE: bCs is only active when cs or rtl is On.
#[test]
fn spec_bcs_without_cs_does_not_produce_bold() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "complex-script-props");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let non_cs = nodes
        .iter()
        .find(|n| n.text.contains("Non-CS bCs"))
        .expect("should find 'Non-CS bCs run'");

    assert!(
        !non_cs.marks.contains(&Mark::Bold),
        "bCs without cs/rtl should NOT produce Bold. Got marks: {:?}",
        non_cs.marks
    );
}

// ── 2. Theme font resolution ────────────────────────────────────────────

/// ISO 29500-1 §17.3.2.26 + §17.8: asciiTheme="minorHAnsi" should resolve
/// to the actual minor font name from theme1.xml.
///
/// python-docx's default (Office 2007) theme maps minorFont latin to "Cambria".
/// POSITIVE: Theme font resolution works for the ascii/hAnsi slot.
#[test]
fn spec_theme_minor_font_resolves() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "theme-font-only");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let minor = nodes
        .iter()
        .find(|n| n.text.contains("Theme minor"))
        .expect("should find 'Theme minor font' run");

    // python-docx default theme: minorFont latin="Cambria"
    assert_eq!(
        minor.style_props.font_family.as_deref(),
        Some("Cambria"),
        "asciiTheme='minorHAnsi' should resolve to 'Cambria' from theme. \
         Got font_family={:?}.",
        minor.style_props.font_family
    );
}

/// ISO 29500-1 §17.8: majorHAnsi theme font should resolve to the major font.
///
/// python-docx's default (Office 2007) theme maps majorFont latin to "Calibri".
/// POSITIVE: Theme font resolution works for the major font.
#[test]
fn spec_theme_major_font_resolves() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "theme-font-only");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let major = nodes
        .iter()
        .find(|n| n.text.contains("Theme major"))
        .expect("should find 'Theme major font' run");

    // python-docx default theme: majorFont latin="Calibri"
    assert_eq!(
        major.style_props.font_family.as_deref(),
        Some("Calibri"),
        "asciiTheme='majorHAnsi' should resolve to 'Calibri' from theme. \
         Got font_family={:?}.",
        major.style_props.font_family
    );
}

/// ISO 29500-1 §17.3.2.26: Theme font resolution for ascii/hAnsi slot works.
///
/// The python-docx default theme has empty eastAsia and cs typefaces, so only
/// ascii/hAnsi resolves to a real font name. This verifies the resolution path.
///
/// POSITIVE: ascii/hAnsi theme resolution is working.
#[ignore = "ISO says empty theme cs → None, but Word falls back to TNR per MS-OI29500 §17.3.2.26c — we follow Word"]
#[test]
fn spec_all_theme_slots_resolve() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "theme-font-only");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let all_slots = nodes
        .iter()
        .find(|n| n.text.contains("All theme slots"))
        .expect("should find 'All theme slots' run");

    // font_family (ascii/hAnsi) should resolve from minorHAnsi → "Cambria"
    assert_eq!(
        all_slots.style_props.font_family.as_deref(),
        Some("Cambria"),
        "asciiTheme='minorHAnsi' should resolve to 'Cambria'. Got {:?}.",
        all_slots.style_props.font_family
    );

    // font_east_asia: theme has ea typeface="" → None (no font defined)
    // This is correct behavior — the theme simply doesn't define an EA font.
    assert!(
        all_slots.style_props.font_east_asia.is_none(),
        "eastAsiaTheme='minorEastAsia' with empty theme ea should be None. \
         Got font_east_asia={:?}.",
        all_slots.style_props.font_east_asia
    );

    // font_cs: theme has cs typeface="" → None (no font defined)
    assert!(
        all_slots.style_props.font_cs.is_none(),
        "csTheme='minorBidi' with empty theme cs should be None. \
         Got font_cs={:?}.",
        all_slots.style_props.font_cs
    );
}

// ── 3. Run border (w:bdr) ───────────────────────────────────────────────

/// ISO 29500-1 §17.3.2.4: Run-level border (w:bdr) should be preserved.
#[test]
fn spec_run_border_preserved() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "run-border");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let bordered = nodes
        .iter()
        .find(|n| n.text.contains("Bordered"))
        .expect("should find 'Bordered run'");

    let border = bordered
        .style_props
        .run_border
        .as_ref()
        .expect("Bordered run should have run_border");
    assert_eq!(border.style, "single", "border style should be 'single'");
    assert_eq!(border.size, 4, "border size should be 4 eighth-points");
    assert_eq!(border.space, 1, "border space should be 1 point");
    assert_eq!(border.color, "FF0000", "border color should be FF0000");
}

// ── 4. w:position (vertical displacement) ───────────────────────────────

/// ISO 29500-1 §17.3.2.24: w:position raises/lowers text by N half-points.
#[test]
fn spec_run_position_preserved() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "run-position");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let raised = nodes
        .iter()
        .find(|n| n.text.contains("Raised"))
        .expect("should find 'Raised text' run");

    assert_eq!(
        raised.style_props.position,
        Some(6),
        "Raised run should have position=6 half-points. Got {:?}",
        raised.style_props.position
    );

    let lowered = nodes
        .iter()
        .find(|n| n.text.contains("Lowered"))
        .expect("should find 'Lowered text' run");

    assert_eq!(
        lowered.style_props.position,
        Some(-4),
        "Lowered run should have position=-4 half-points. Got {:?}",
        lowered.style_props.position
    );
}

