// ── 7. w:rtl font slot forcing ──────────────────────────────────────────

/// MS-OI29500 §17.3.2.26(b): w:rtl=true forces cs font slot for all characters.
///
/// POSITIVE: The style resolver replaces font_family with font_cs when rtl=On.
#[test]
fn spec_rtl_forces_cs_font_slot() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "rtl-run");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let rtl = nodes
        .iter()
        .find(|n| n.text.contains("RTL run"))
        .expect("should find 'RTL run'");

    // rtl=true: font_family should be the cs font "David", not ascii "Arial"
    assert_eq!(
        rtl.style_props.font_family.as_deref(),
        Some("David"),
        "rtl=true run should use cs font 'David' as font_family, \
         not ascii font 'Arial'. Got font_family={:?}",
        rtl.style_props.font_family
    );
}

/// Positive test: non-RTL run uses ascii font slot.
#[test]
fn spec_non_rtl_uses_ascii_font() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "rtl-run");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let ltr = nodes
        .iter()
        .find(|n| n.text.contains("LTR run"))
        .expect("should find 'LTR run'");

    // No rtl: font_family should be ascii font "Arial"
    assert_eq!(
        ltr.style_props.font_family.as_deref(),
        Some("Arial"),
        "non-RTL run should use ascii font 'Arial'. Got font_family={:?}",
        ltr.style_props.font_family
    );
}

// ── 8. Multiple font slots ──────────────────────────────────────────────

/// ISO 29500-1 §17.3.2.26: Each rFonts slot should be independently captured.
///
/// POSITIVE: font_family, font_east_asia, and font_cs are all parsed.
#[test]
fn spec_multi_font_slots_all_captured() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "multi-font-slots");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let run = nodes
        .iter()
        .find(|n| n.text.contains("Multi-font"))
        .expect("should find 'Multi-font run'");

    assert_eq!(
        run.style_props.font_family.as_deref(),
        Some("Courier New"),
        "ascii/hAnsi font should be 'Courier New'. Got {:?}",
        run.style_props.font_family
    );
    assert_eq!(
        run.style_props.font_east_asia.as_deref(),
        Some("MS Mincho"),
        "eastAsia font should be 'MS Mincho'. Got {:?}",
        run.style_props.font_east_asia
    );
    assert_eq!(
        run.style_props.font_cs.as_deref(),
        Some("Traditional Arabic"),
        "cs font should be 'Traditional Arabic'. Got {:?}",
        run.style_props.font_cs
    );
}
